VALUES
  ('cpa-moex-00018', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者並非公司法明定之股份有限公司股東會召集權人？', '["監察人", "繼續3個月以上持有已發行股份總數過半數股份之股東", "董事長", "董事會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00019', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者為董事缺額時，股份有限公司應盡速召開股東臨時會補選之最低門檻？', '["全部退任", "三分之二", "過半", "三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00020', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A興櫃公司因其獨到的商業模式獲得廣大消費者的青睞，故欲上市募資以加速擴大其通路的市占 率。下列關於證券交易法及相關規定的說明，何者正確？', '["甲股東持有A公司相當大量的特別股，若於該公司上市前公開對不特定投資人介紹、勸誘購買 其出售的股份，也須向主管機關申報生效", "本法既採申報生效制，主管機關指定之機關即使基於公益必要原因，要求A公司在上市過程中 補正說明，仍應在收到申請書件即日起屆滿一定營業日，即讓其生效、不得有所延遲", "A公司上市案件經申報生效後，乙董事長即可在與外國機構投資人的公開聚會上，表示我國政 府亦認同申報書件內所提之商業模式廣獲市場青睞", "A公司曾於上市前公開對不特定人招募出售該公司的認股權憑證，因尚未上市，故尚無須向主 管機關申報生效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00021', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '承上題，A公司於上市後，又有籌資需求，故再度增資以現金發行新股。就股權分散規定之說明， 下列敘述何者正確？', '["倘A公司臨時發現公司有大量盈餘，決定改以盈餘撥充資本的方式發行，此時仍應提撥發行新 股總額的一定比率，對外公開發行", "A公司發行新股時，不須讓員工依公司法承購發行新股總數百分之十至十五的股份", "A公司發行新股時，須提撥至少百分之十的新股由原股東依原有股份比例儘先分認，其餘的新 股強制對外公開發行", "若A公司擬向外以每股53元的價格發行新股，有部分員工要求以每股52元認購，A公司則回 應以53元認購，始為合法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00022', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為股票上市A公司董事，欲於集中交易市場出售持股，得免向主管機關申報之每日出售數量上 限為何？', '["一千股", "三千股", "五千股", "一萬股"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00023', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司為向投資大眾籌募資金，申請股票上櫃交易，下列敘述何者正確？', '["A公司應達經濟部規定之規模，方得申請上櫃交易", "A公司通過股票上櫃審查後，應與證券櫃檯買賣中心簽訂上櫃契約", "上櫃契約應經證券主管機關核准始生效力", "股票上櫃買賣後，原則上依法不得進行場外交易"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00024', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '新冠肺炎疫情造成全球晶片短缺，A上市半導體公司因而業績亮眼，股價長紅，甲在郵局工作， 得知同事乙持有A公司股票3張欲獲利了結，便私下先向乙買入其中1張，甲、乙間之交易行為 是否合法？', '["違法，因A公司為上市公司，其股票買賣應委託證券經紀商辦理", "違法，因A公司為上市公司，其股票買賣應於集中交易市場為之", "合法，但甲須於向主管機關申報之日起3日內買入", "合法，因乙於3個月內僅轉讓1張A公司股票給甲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00025', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依據證券交易法，公開發行公司召集股東會時，下列何事項應在召集事由中列舉並說明其主要內 容，不得以臨時動議提出？', '["決議對董事提起訴訟", "實施庫藏股制度", "選任臨時管理人", "董事競業禁止之解除"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00026', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法之規定，下列何者不是上市公司得買回其股份之原因？', '["為維護公司信用及股東權益所必要而買回", "只要有股東要求公司買回時，無論其理由為何，公司即必須買回", "為轉讓股份予員工", "為配合可轉換公司債之發行，作為股權轉換之用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00027', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上櫃公司的董事長甲，為了實踐公開揭露原則，使得投資大眾能夠及時獲得有效且透明的公司 資料，特別要求公司會計部門主管乙，一定要遵守證券交易法之相關規定。下列敘述何者錯誤？', '["A公司應於每會計年度終了後三個月內，公告並申報經會計師查核簽證、董事會通過及監察人 承認之年度財務報告", "A公司應於每會計年度第一季、第二季及第三季終了後三十日內，公告並申報經會計師核閱及 提報董事會之財務報告", "A公司應於每月十日以前，公告並申報上月份營運情形", "若股東常會承認之年度財務報告與公告並向主管機關申報之年度財務報告不一致時，A公司應 於事實發生之日起二日內公告並向主管機關申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00028', 'cpa', 'cpa-moex-114-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '在A公開發行公司服務之甲，於2020年10月至2022年1月間，連續利用業務上機會，以反覆 挪用方式連續侵占公司資金，雖有歸還一部分金額，實際侵占金額仍達新臺幣數百萬元之多。下 列敘述何者正確？', '["當甲具董事身分時，其侵占致公司遭受損害金額達新臺幣五百萬元以上，應依證券交易法第171 條處罰", "當甲具董事身分時，其侵占致公司遭受損害，不論金額高低，均應依證券交易法第171條處罰", "不論甲為公司董事或受僱人，其侵占致公司遭受損害金額達新臺幣五百萬元以上，均應依證券 交易法第171條處罰", "不論甲為公司董事或受僱人，其侵占致公司遭受損害，不論金額高低，均應依證券交易法第171 條處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:28:57+00:00", "source_pdf_sha1": "4d102b2568f0", "answer_pdf_sha1": "6170bd6fe443", "source_family": "moex-gov-tw", "moex": {"exam_code": "114130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "114", "exam_name": "114年專門職業及技術人員高等考試會計師、不動產估價師、專利師、植物診療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
